<template>
    <div class="mycontainer">
      <form @submit.prevent="post">
        <div class="top">
            <div class="left">
                <img v-if="selectedImg" :src="selectedImg" alt="">
                <button v-else  @click="ofi">+</button>
            </div>
            <div class="right">
                <input type="text" name="title" v-model="title" placeholder="Enter Title" class="form-control">
                <input type="text" name="cate" v-model="cate" placeholder="Enter Category" class="form-control">
                <input type="file" name="img" accept="image/*" placeholder="insert image" style="display: none;" @change="hiu" ref="fi">
                <textarea class="form-control" name="content" v-model="content" id="" cols="30" rows="10" placeholder="Enter Content Here"></textarea>
            </div>
        </div>
        <input type="submit" value="Submit" class="btn btn-theme mt-3 wow fadeInUp ml-1" @click="createblog">
      </form>
    </div>
</template>

<script>
  import { mapState, mapActions } from 'vuex';
  export default {
    data() {
      return {
        credentials:{
          title: null,
          cate: null,
          img: null,
          content: null,
          selectedImage: null
        },
        bfs: false
       }
    },
    computed: {
      ...mapState('auth', ['returnmessage']),
    },
    mounted(){
        

    },
    methods:{
        ...mapActions('auth', ['addBlog']),
        async createblog(){
        try{
            const formData = new FormData();
                formData.append('title', this.credentials.title);
                formData.append('cate', this.credentials.cate);
                formData.append('img', this.credentials.img);
                formData.append('content', this.credentials.content);
            await this.addBlog(formData);
                if (this.returnmessage){
                    this.loading = false
                }
                else{
                    alert('We have a problem')
                }
            }
            catch (error){
                console.error( 'Error', error);
            }
      },
      ofi(){
        this.$refs.fi.click();
      },
      hiu(event){
        this.credentials.img = event.target.files[0]
        console.log(this.credentials.img)
        const file = event.target.files[0]
        localStorage.setItem('selectedImage', file)
        this.picker()
      },
      picker(){
        const storedImage = localStorage.getItem('selectedImage');
        this.selectedImage = storedImage
      }
    }
  }
</script>

<style scoped>
.top{
    display: flex;
    flex-direction: row;
    gap: 10px;
}
.left{
    width: 300px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    background-color: white;
}
.mycontainer{
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background-color: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 999;
}
</style>