<template>
    <div class="vg-page page-portfolio" id="portfolio">
        <div class="container">
            <div class="text-center wow fadeInUp">
                <div class="badge badge-subhead">Portfolio</div>
            </div>
            <h1 class="text-center fw-normal wow fadeInUp">See my work</h1>
            <div class="filterable-button py-3 wow fadeInUp" data-toggle="selected">          
                <button class="btn btn-theme-outline selected" @click="changeCategory('All')">All</button>
                <button v-for="(choice, index) in choices" :key="index" class="btn btn-theme-outline" @click="changeCategory(choice)">
                    {{choice}}
                </button>
            </div>
            <div class="gridder my-3">
                <div v-for="project in filteredData.slice(0,6)" :key="project.id" class="grid-item wow zoomIn" :class="project.status">
                    <a class="img-place" :data-src="project.img" :href="project.url">
                        <img :src="project.img" alt="">
                        <div class="img-caption">
                            <h5 class="fg-theme">{{ project.name }}</h5>
                            <p>{{ project.about }}</p>
                        </div>
                    </a>
                </div>
            </div> 
        </div>
    </div>
    <div class="text-center wow fadeInUp lali">
        <router-link to="projects" class="btn btn-theme">See All</router-link>
    </div>
</template>

<style>
    .lali{
        margin-top: -1rem;
    }
</style>

<script>
  import { mapGetters, mapMutations } from 'vuex';
    export default{
    computed:{
        ...mapGetters('details', ['choices', 'filteredData'] )
    },
    created(){
        this.setCategory('All')
    },
    methods:{
        ...mapMutations('details', ['setCategory']),
        changeCategory(category){
            this.setCategory(category)
        }
    }
}
</script>