import axios from 'axios';

const state = {
    details: null,
    files: null,
    socials: null,
    cskills: null,
    dskills: null,
    edu: null,
    exp: null,
    services: null,
    allprojects: [],
    loading: true,
    contactmessage: null,
    selectedCategory: 'All',
    sortby: 'title',
    currentPage: 1,
    itemsPerPage: 6,
    searchTerm: null
};
const getters = {
    searchData: (state) => {
        const allData = state.allprojects;
        const key = state.searchTerm;
        if (key === null || key === ''){
            return allData;
        }
        const newData =  allData.filter(item =>
            item.name.toLowerCase().includes(key.toLowerCase()))
        return newData
    },
    filteredData: (state, getters) => {
        const allSearches = getters.searchData
        const category = state.selectedCategory
        if(category === 'All'){
            return allSearches
        }
        return allSearches.filter(item => item.status === category);
    },
    sortedData:(state, getters) =>{
    const filteredArray = [...getters.filteredData];
    return filteredArray.sort((a, b) => {
        if (state.sortby === 'title') {
            return a.name.localeCompare(b.name);
        } else if (state.sortby === 'date') {
            return new Date(a.date) - new Date(b.date);
        }
    });
    },
    paginatedData: (state, getters) => {
    const sortedArray = [...getters.sortedData];
    const startIndex = (state.currentPage - 1) * state.itemsPerPage;
    const endIndex = startIndex + state.itemsPerPage;
    return sortedArray.slice(startIndex, endIndex)
    },
    choices: (state) => {
        const mychoices = new Set();
        for (const choice of state.allprojects) {
                mychoices.add(choice.status);
        }
        return Array.from(mychoices);
    },
    TotalPages: (state, getters) => {
        const sortedArray = [...getters.sortedData];
        const totalItems = sortedArray.length;
        const totalPages = Math.ceil(totalItems / state.itemsPerPage);
        return totalPages;
    },
    details: (state) => {
        const det = state.details
        const dataDict = {};
        for (const item of det) {
          dataDict[item.name] = item.detail;
        }
        return dataDict;
      },
    files: (state) => {
        const det = state.files
        const dataDict = {};
        for (const item of det) {
          dataDict[item.name] = item.file;
        }
        return dataDict;
      },
    socials: (state) => {
        const det = state.socials
        const dataObject = {};
        for (const item of det) {
          dataObject[item.name] = {
            url: item.url,
            handle: item.handle,
          };
        }
        return dataObject;
      },
}
const mutations = {
    setCpage(state, key){
        state.currentPage = key
    },
    setKey(state, key){
        state.searchTerm = key
    },
    setCmsg(state, contactmessage){
        state.contactmessage = contactmessage
    },
    setDskills(state, dskills){
        state.dskills = dskills
    },
    setExp(state, exp){
        state.exp = exp
    },
    setEdu(state, edu){
        state.edu = edu
    },
    setAllprojects(state, allprojects){
        state.allprojects = allprojects
    },
    setCategory(state, status){
        state.selectedCategory =  status
    },
    setSorting(state, status){
        state.sortby =  status
    },
    setPages(state, status){
        state.currentPage =  status
    },
    setCskills(state, cskills){
        state.cskills= cskills;
    },
    setData(state, loading){
        state.loading = loading
    },
    setFiles(state, files){
        state.files = files
    },
    setSocials(state, socials){
        state.socials = socials
    },
    setDetail(state, details){
        state.details = details
    }
};

const actions = {
    async fetchDataFromDjango({commit}) {
        try {
            const coding = await axios.get('https://vorteks.pythonanywhere.com/api/codingskills/')
            const design = await axios.get('https://vorteks.pythonanywhere.com/api/designskills/')
            const education = await axios.get('https://vorteks.pythonanywhere.com/api/education/')
            const experience = await axios.get('https://vorteks.pythonanywhere.com/api/experience/')
            const portfolio = await axios.get('https://vorteks.pythonanywhere.com/api/portfolio/')
            const details = await axios.get('https://vorteks.pythonanywhere.com/api/detail/')
            const files = await axios.get('https://vorteks.pythonanywhere.com/api/files/')
            const socials = await axios.get('https://vorteks.pythonanywhere.com/api/socials/')
            commit('setCskills', coding.data)
            commit('setDskills', design.data)
            commit('setEdu', education.data)
            commit('setExp', experience.data)
            commit('setAllprojects', portfolio.data)
            commit('setDetail', details.data)
            commit('setFiles', files.data)
            commit('setSocials', socials.data)
            commit('setData', false)
        }
        catch(error) {
            console.error(error);
    }
},
    async submitForm({commit}, credentials){
        try{
           const response = await axios.post(`https://vorteks.pythonanywhere.com/api/contactform/`, credentials,{
            headers: {
            'Content-Type': 'application/json',
            },
           })
           if (response.status === 200){
            commit('setCmsg', true)
           }
           else{
            commit('setCmsg', false)
           }
        } catch(error){
            console.log(error)
        }
    }
};

export default {
  namespaced: true,
  state,
  mutations,
  actions,
  getters
};
