<template>
    <div class="vg-page page-home" :style="{ backgroundImage: `url(${bg})` }">
        <div class="caption wow zoomInUp">
            <h1 class="fw-normal">Welcome</h1>
            <h2 class="fw-medium fg-theme">I'm {{ nickname }}</h2>
            <p class="tagline">{{ job }}</p>
        </div>
    </div>
</template>

<style>
.vg-page {
    position: relative;
    padding: 70px 16px;
    color: #858B91;
    z-index: 10;
    overflow: hidden;
}
.page-home {
    display: block;
    width: 100%;
    height: 100vh;
    background-repeat: no-repeat;
    background-size: cover;
    background-position: center center;
    overflow: hidden;
}

.page-home::before {
    content: "";
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 2;
}

.page-home .caption {
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    height: 100%;
    z-index: 10;
}

.page-home .caption h1 {
    font-size: 3rem;
}

.page-home .caption .tagline {
    margin-top: 8px;
    padding: 15px 40px;
    background-color: #fddbd7;
    color: #EF3724;
    border-radius: 40px;
    font-weight: 500;
    font-size: 18px;
}
</style>
    
<script>
  import { mapGetters } from 'vuex';
    export default{
        computed:{
        ...mapGetters('details',['details', 'files']),
        nickname() {
            return this.details['Nickname'];
        },
        job() {
            return this.details['Job Description'];
        },
        bg(){
            return this.files['Main Bg'];
        }
        }
    }
</script>